class Solution {
    public int maxConsecutiveAnswers(String answerKey, int k) {
        int n = answerKey.length();
        int maxT = 0, maxF = 0;
        int left = 0, countT = 0, countF = 0;
        for (int right = 0; right < n; right++) {
            char c = answerKey.charAt(right);
            if (c == 'T') countT++;
            else countF++;
            while (Math.max(countT, countF) > k) {
                char leftC = answerKey.charAt(left);
                if (leftC == 'T') countT--;
                else countF--;
                left++;
            }
            maxT = Math.max(maxT, right - left + 1);
            maxF = Math.max(maxF, right - left + 1);
        }
        return Math.max(maxT, maxF);
    }
}
